export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export async function blobToBase64(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ContentEmpireOutput } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getGeminiClient = () => {
  if (!API_KEY) throw new Error("Missing Gemini API Key");
  return new GoogleGenAI({ apiKey: API_KEY });
};

export async function transcribeAudio(base64Audio: string): Promise<string> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          { inlineData: { mimeType: 'audio/webm', data: base64Audio } },
          { text: "Transcribe this audio exactly. Just the text, no extra comments." }
        ]
      }
    ]
  });
  return response.text || "Transcription failed.";
}

export async function generateContentEmpire(transcription: string): Promise<ContentEmpireOutput> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Based on the following voice memo transcription: "${transcription}", generate a content package for a personal brand of a professional business speaker. Output in JSON format only.

    Format:
    {
      "reelsScript": {
        "hook": "Strong attention-grabber",
        "body": "Value-packed short script",
        "visuals": ["Scene 1 description", "Scene 2 description"],
        "cta": "Call to action"
      },
      "instagramPost": {
        "caption": "Engaging IG caption with emojis",
        "hashtags": ["#tag1", "#tag2"]
      },
      "linkedInArticle": {
        "title": "Professional Title",
        "content": "Deep-dive professional article text"
      },
      "storyIdeas": ["Idea 1", "Idea 2", "Idea 3", "Idea 4", "Idea 5"]
    }`,
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 10000 },
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          reelsScript: {
            type: Type.OBJECT,
            properties: {
              hook: { type: Type.STRING },
              body: { type: Type.STRING },
              visuals: { type: Type.ARRAY, items: { type: Type.STRING } },
              cta: { type: Type.STRING }
            },
            required: ['hook', 'body', 'visuals', 'cta']
          },
          instagramPost: {
            type: Type.OBJECT,
            properties: {
              caption: { type: Type.STRING },
              hashtags: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ['caption', 'hashtags']
          },
          linkedInArticle: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              content: { type: Type.STRING }
            },
            required: ['title', 'content']
          },
          storyIdeas: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['reelsScript', 'instagramPost', 'linkedInArticle', 'storyIdeas']
      }
    }
  });

  return JSON.parse(response.text || "{}");
}

export async function speakText(text: string): Promise<string> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Read this content professionally: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
}

import React, { useState } from 'react';
import { Play, Copy, Check, Loader2, Volume2 } from 'lucide-react';
import { speakText } from '../services/geminiService';
import { decode, decodeAudioData } from '../utils/audioUtils';

interface ContentCardProps {
  title: string;
  icon: React.ReactNode;
  content: string;
  subContent?: string[];
}

const ContentCard: React.FC<ContentCardProps> = ({ title, icon, content, subContent }) => {
  const [copied, setCopied] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSpeak = async () => {
    if (isSpeaking) return;
    setIsSpeaking(true);
    try {
      const base64Audio = await speakText(content);
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await decodeAudioData(decode(base64Audio), audioCtx, 24000, 1);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setIsSpeaking(false);
      source.start();
    } catch (error) {
      console.error("Speech error:", error);
      setIsSpeaking(false);
    }
  };

  return (
    <div className="glass-card rounded-2xl p-6 transition-all hover:border-amber-500/30">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-amber-500/10 rounded-lg text-amber-500">
            {icon}
          </div>
          <h3 className="font-bold text-lg text-white">{title}</h3>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleSpeak}
            disabled={isSpeaking}
            className="p-2 hover:bg-white/5 rounded-full transition-colors text-zinc-400 hover:text-amber-500"
          >
            {isSpeaking ? <Loader2 size={18} className="animate-spin" /> : <Volume2 size={18} />}
          </button>
          <button 
            onClick={handleCopy}
            className="p-2 hover:bg-white/5 rounded-full transition-colors text-zinc-400 hover:text-white"
          >
            {copied ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        <p className="text-zinc-300 leading-relaxed whitespace-pre-wrap">
          {content}
        </p>

        {subContent && subContent.length > 0 && (
          <div className="pt-4 border-t border-white/5">
            <h4 className="text-xs font-semibold text-zinc-500 uppercase tracking-wider mb-2">Details</h4>
            <ul className="space-y-2">
              {subContent.map((item, i) => (
                <li key={i} className="flex gap-2 text-sm text-zinc-400">
                  <span className="text-amber-500/50">•</span>
                  {item}
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </div>
  );
};

export default ContentCard;

import React, { useState, useRef, useEffect } from 'react';
import { Mic, MicOff, BrainCircuit, Loader2 } from 'lucide-react';
import { getGeminiClient } from '../services/geminiService';
import { encode, decode, decodeAudioData } from '../utils/audioUtils';
import { Modality, LiveServerMessage } from '@google/genai';

const LiveStrategist: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [transcript, setTranscript] = useState<{ role: 'user' | 'ai'; text: string }[]>([]);

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startSession = async () => {
    setIsConnecting(true);
    try {
      const ai = getGeminiClient();
      streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });

      audioContextRef.current = new AudioContext({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);
            const source = audioContextRef.current!.createMediaStreamSource(streamRef.current!);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }

            // Note: In real app, we'd handle transcription here if enabled
          },
          onerror: (e) => console.error("Live API Error:", e),
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: "You are the Personal Brand Strategist for a high-level business speaker. Your goal is to help them brainstorm content ideas, refine their voice, and structure their thinking. Be energetic, strategic, and professional.",
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    if (sessionRef.current) sessionRef.current.close();
    if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    setIsActive(false);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <div className="glass-card rounded-3xl p-12 text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-amber-500 to-red-500"></div>

        <div className="flex flex-col items-center gap-6">
          <div className={`p-6 rounded-full ${isActive ? 'bg-amber-500/20 text-amber-500 animate-pulse' : 'bg-white/5 text-zinc-400'}`}>
            <BrainCircuit size={48} />
          </div>

          <div>
            <h2 className="text-3xl font-bold text-white mb-2">Brand Strategist Live</h2>
            <p className="text-zinc-400 max-w-md mx-auto">
              {isActive ? "Strategist is listening. Talk about your ideas or challenges." : "Brainstorm your next big move in real-time with your personal AI strategist."}
            </p>
          </div>

          <button
            onClick={isActive ? stopSession : startSession}
            disabled={isConnecting}
            className={`mt-4 px-10 py-5 rounded-full font-bold flex items-center gap-3 transition-all ${
              isActive 
              ? 'bg-red-500 hover:bg-red-600 text-white' 
              : 'bg-amber-500 hover:bg-amber-600 text-zinc-900 glow-button'
            }`}
          >
            {isConnecting ? <Loader2 className="animate-spin" /> : (isActive ? <MicOff /> : <Mic />)}
            {isConnecting ? "Connecting..." : (isActive ? "Stop Strategizing" : "Start Conversation")}
          </button>

          {isActive && (
            <div className="mt-8 flex gap-1 items-center">
              <div className="w-1 h-4 bg-amber-500 animate-bounce delay-75"></div>
              <div className="w-1 h-8 bg-amber-500 animate-bounce delay-150"></div>
              <div className="w-1 h-12 bg-amber-500 animate-bounce delay-300"></div>
              <div className="w-1 h-8 bg-amber-500 animate-bounce delay-150"></div>
              <div className="w-1 h-4 bg-amber-500 animate-bounce delay-75"></div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default LiveStrategist;

import React, { useState, useRef } from 'react';
