    Ввод может быть на русском или таджикском языке. Вывод (контент) должен быть на русском языке, но адаптирован под культурный контекст автора.
    Выведи результат строго в формате JSON.

    Формат:
    {
      "reelsScript": {
        "hook": "Сильный зацеп (hook)",
        "body": "Текст сценария",
        "visuals": ["Описание сцены 1", "Описание сцены 2"],
        "cta": "Призыв к действию"
      },
      "instagramPost": {
        "caption": "Увлекательная подпись с эмодзи",
        "hashtags": ["#тег1", "#тег2"]
      },
      "linkedInArticle": {
        "title": "Профессиональный заголовок",
        "content": "Текст глубокой профессиональной статьи"
      },
      "storyIdeas": ["Идея 1", "Идея 2", "Идея 3", "Идея 4", "Идея 5"]
    }`,
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 10000 },
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          reelsScript: {
            type: Type.OBJECT,
            properties: {
              hook: { type: Type.STRING },
              body: { type: Type.STRING },
              visuals: { type: Type.ARRAY, items: { type: Type.STRING } },
              cta: { type: Type.STRING }
            },
            required: ['hook', 'body', 'visuals', 'cta']
          },
          instagramPost: {
            type: Type.OBJECT,
            properties: {
              caption: { type: Type.STRING },
              hashtags: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ['caption', 'hashtags']
          },
          linkedInArticle: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              content: { type: Type.STRING }
            },
            required: ['title', 'content']
          },
          storyIdeas: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['reelsScript', 'instagramPost', 'linkedInArticle', 'storyIdeas']
      }
    }
  });

  return JSON.parse(response.text || "{}");
}

export async function speakText(text: string): Promise<string> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Прочитай этот контент профессионально и четко: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
}

import React, { useState } from 'react';
import { Play, Copy, Check, Loader2, Volume2 } from 'lucide-react';
import { speakText } from '../services/geminiService';
import { decode, decodeAudioData } from '../utils/audioUtils';

interface ContentCardProps {
  title: string;
  icon: React.ReactNode;
  content: string;
  subContent?: string[];
}

const ContentCard: React.FC<ContentCardProps> = ({ title, icon, content, subContent }) => {
  const [copied, setCopied] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSpeak = async () => {
    if (isSpeaking) return;
    setIsSpeaking(true);
    try {
      const base64Audio = await speakText(content);
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await decodeAudioData(decode(base64Audio), audioCtx, 24000, 1);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setIsSpeaking(false);
      source.start();
    } catch (error) {
      console.error("Ошибка озвучки:", error);
      setIsSpeaking(false);
    }
  };

  return (
    <div className="glass-card rounded-2xl p-6 transition-all hover:border-amber-500/30">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-amber-500/10 rounded-lg text-amber-500">
            {icon}
          </div>
          <h3 className="font-bold text-lg text-white">{title}</h3>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleSpeak}
            disabled={isSpeaking}
            title="Озвучить"
            className="p-2 hover:bg-white/5 rounded-full transition-colors text-zinc-400 hover:text-amber-500"
          >
            {isSpeaking ? <Loader2 size={18} className="animate-spin" /> : <Volume2 size={18} />}
          </button>
          <button 
            onClick={handleCopy}
            title="Копировать"
            className="p-2 hover:bg-white/5 rounded-full transition-colors text-zinc-400 hover:text-white"
          >
            {copied ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        <p className="text-zinc-300 leading-relaxed whitespace-pre-wrap">
          {content}
        </p>

        {subContent && subContent.length > 0 && (
          <div className="pt-4 border-t border-white/5">
            <h4 className="text-xs font-semibold text-zinc-500 uppercase tracking-wider mb-2">Детали</h4>
            <ul className="space-y-2">
              {subContent.map((item, i) => (
                <li key={i} className="flex gap-2 text-sm text-zinc-400">
                  <span className="text-amber-500/50">•</span>
                  {item}
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </div>
  );
};

export default ContentCard;

import React, { useState, useRef } from 'react';
import { Mic, MicOff, BrainCircuit, Loader2 } from 'lucide-react';
import { getGeminiClient } from '../services/geminiService';
import { encode, decode, decodeAudioData } from '../utils/audioUtils';
import { Modality, LiveServerMessage } from '@google/genai';

const LiveStrategist: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startSession = async () => {
    setIsConnecting(true);
    try {
      const ai = getGeminiClient();
      streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });

      audioContextRef.current = new AudioContext({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);
            const source = audioContextRef.current!.createMediaStreamSource(streamRef.current!);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => console.error("Ошибка Live API:", e),
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: "Ты — Стратег Личного Бренда для высокоуровневого бизнес-спикера. Ты отлично понимаешь русский и таджикский языки. Твоя задача — помогать пользователю генерировать идеи, оттачивать голос бренда и структурировать мысли. Отвечай на том же языке, на котором говорит пользователь. Будь энергичным, стратегическим и профессиональным.",
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    if (sessionRef.current) sessionRef.current.close();
    if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    setIsActive(false);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <div className="glass-card rounded-3xl p-12 text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-amber-500 to-red-500"></div>

        <div className="flex flex-col items-center gap-6">
          <div className={`p-6 rounded-full ${isActive ? 'bg-amber-500/20 text-amber-500 animate-pulse' : 'bg-white/5 text-zinc-400'}`}>
            <BrainCircuit size={48} />
          </div>

          <div>
            <h2 className="text-3xl font-bold text-white mb-2">Бренд-Стратег Live</h2>
            <p className="text-zinc-400 max-w-md mx-auto">
              {isActive ? "Стратег слушает. Расскажите о ваших идеях или проблемах." : "Разрабатывайте стратегию в реальном времени с вашим личным ИИ-стратегом. Понимает русский и таджикский."}
            </p>
          </div>

          <button
            onClick={isActive ? stopSession : startSession}
            disabled={isConnecting}
            className={`mt-4 px-10 py-5 rounded-full font-bold flex items-center gap-3 transition-all ${
              isActive 
              ? 'bg-red-500 hover:bg-red-600 text-white' 
              : 'bg-amber-500 hover:bg-amber-600 text-zinc-900 glow-button'
            }`}
          >
            {isConnecting ? <Loader2 className="animate-spin" /> : (isActive ? <MicOff /> : <Mic />)}
            {isConnecting ? "Подключение..." : (isActive ? "Завершить сессию" : "Начать разговор")}
          </button>

          {isActive && (
            <div className="mt-8 flex gap-1 items-center">
              <div className="w-1 h-4 bg-amber-500 animate-bounce delay-75"></div>
              <div className="w-1 h-8 bg-amber-500 animate-bounce delay-150"></div>
              <div className="w-1 h-12 bg-amber-500 animate-bounce delay-300"></div>
              <div className="w-1 h-8 bg-amber-500 animate-bounce delay-150"></div>
              <div className="w-1 h-4 bg-amber-500 animate-bounce delay-75"></div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default LiveStrategist;

import React, { useState, useRef } from 'react';
import { 
  Mic, 
  Square, 
  Sparkles, 
  Video, 
  Instagram, 
  Linkedin, 
  LayoutGrid, 
  BrainCircuit,
  Loader2,
  AlertCircle
} from 'lucide-react';
import { AppTab, ContentEmpireOutput } from './types';
import { transcribeAudio, generateContentEmpire } from './services/geminiService';
import { blobToBase64 } from './utils/audioUtils';
import ContentCard from './components/ContentCard';
import LiveStrategist from './components/LiveStrategist';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.FACTORY);
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<ContentEmpireOutput | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      recorder.onstop = async () => {
        const audioBlob = new Blob(chunksRef.current, { type: 'audio/webm' });
        processAudio(audioBlob);
      };

      recorder.start();
      setIsRecording(true);
      setError(null);
    } catch (err) {
      setError("Пожалуйста, разрешите доступ к микрофону для записи идей.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
    }
  };

  const processAudio = async (blob: Blob) => {
    setIsProcessing(true);
    try {
      const base64 = await blobToBase64(blob);
      const transcription = await transcribeAudio(base64);
      const content = await generateContentEmpire(transcription);
      setResults(content);
    } catch (err: any) {
      setError(err.message || "Не удалось обработать аудио. Попробуйте еще раз.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Навигация */}
      <nav className="sticky top-0 z-50 glass-card border-b border-white/5 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-gradient-to-br from-amber-500 to-red-500 rounded-xl flex items-center justify-center text-zinc-900 shadow-lg shadow-amber-500/20">
            <Sparkles size={24} strokeWidth={2.5} />
          </div>
          <span className="text-xl font-bold tracking-tight uppercase">ФАБРИКА <span className="gradient-text">БРЕНДА</span></span>
        </div>

        <div className="flex bg-white/5 rounded-full p-1 border border-white/10">
          <button 
            onClick={() => setActiveTab(AppTab.FACTORY)}
            className={`flex items-center gap-2 px-6 py-2 rounded-full text-sm font-medium transition-all ${activeTab === AppTab.FACTORY ? 'bg-amber-500 text-zinc-900 shadow-md' : 'text-zinc-400 hover:text-white'}`}
          >
            <LayoutGrid size={18} />
            Фабрика
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.STRATEGIST)}
            className={`flex items-center gap-2 px-6 py-2 rounded-full text-sm font-medium transition-all ${activeTab === AppTab.STRATEGIST ? 'bg-amber-500 text-zinc-900 shadow-md' : 'text-zinc-400 hover:text-white'}`}
          >
            <BrainCircuit size={18} />
            Стратег
          </button>
        </div>
      </nav>

      {/* Контент */}
      <main className="container mx-auto max-w-6xl mt-8">
        {activeTab === AppTab.FACTORY && (
          <div className="px-4 space-y-12">
            {/* Секция записи */}
            <div className="text-center py-12">
              <h1 className="text-5xl font-black mb-4 tracking-tight leading-tight">Превратите свои мысли в <br/><span className="gradient-text">контент-империю</span></h1>
              <p className="text-zinc-400 text-lg mb-10 max-w-2xl mx-auto">Запишите быструю 2-минутную идею (на русском или таджикском). ИИ возьмет на себя сценарии, посты и стратегию.</p>

              <div className="flex flex-col items-center gap-6">
                <button
                  onClick={isRecording ? stopRecording : startRecording}
                  disabled={isProcessing}
                  className={`w-28 h-28 rounded-full flex items-center justify-center transition-all duration-300 transform active:scale-95 shadow-2xl ${
                    isRecording 
                    ? 'bg-red-500 animate-pulse ring-8 ring-red-500/20' 
                    : 'bg-amber-500 hover:bg-amber-600 glow-button'
                  }`}
                >
                  {isRecording ? <Square size={36} fill="white" stroke="white" /> : <Mic size={36} className="text-zinc-900" strokeWidth={2.5} />}
                </button>

                <div className="flex flex-col items-center">
                  <span className={`text-sm font-bold tracking-widest uppercase transition-colors ${isRecording ? 'text-red-500' : 'text-zinc-500'}`}>
                    {isRecording ? "Слушаю вашу гениальность..." : isProcessing ? "Строю вашу империю..." : "Нажмите, чтобы записать идею"}
                  </span>
                  {isRecording && <span className="text-xs text-red-500/60 mt-2">Говорите четко • рекомендуем до 2 мин</span>}
                </div>
              </div>
            </div>

            {error && (
              <div className="flex items-center gap-3 bg-red-500/10 border border-red-500/20 p-4 rounded-xl text-red-500 max-w-md mx-auto">
                <AlertCircle size={20} />
                <p className="text-sm font-medium">{error}</p>
              </div>
            )}

            {isProcessing && (
              <div className="flex flex-col items-center justify-center gap-4 py-20">
                <Loader2 size={48} className="text-amber-500 animate-spin" />
                <p className="text-zinc-400 animate-pulse font-medium">Gemini анализирует ваши мысли...</p>
              </div>
            )}

            {results && !isProcessing && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pb-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <ContentCard 
                  title="Сценарий Reels" 
                  icon={<Video size={20} />} 
                  content={`${results.reelsScript.hook}\n\n${results.reelsScript.body}\n\nПризыв: ${results.reelsScript.cta}`}
                  subContent={results.reelsScript.visuals}
                />
                <ContentCard 
                  title="Пост в Instagram" 
                  icon={<Instagram size={20} />} 
                  content={results.instagramPost.caption}
                  subContent={results.instagramPost.hashtags}
                />
                <ContentCard 
                  title="Статья в LinkedIn" 
                  icon={<Linkedin size={20} />} 
                  content={`${results.linkedInArticle.title}\n\n${results.linkedInArticle.content}`}
                />
                <ContentCard 
                  title="Идеи для Stories (на 5 дней)" 
                  icon={<Sparkles size={20} />} 
                  content="Ваша стратегия вовлечения:"
                  subContent={results.storyIdeas}
                />
              </div>
            )}
          </div>
        )}

        {activeTab === AppTab.STRATEGIST && (
          <LiveStrategist />
        )}
      </main>

      {/* Футер */}
      <footer className="fixed bottom-0 left-0 right-0 glass-card py-3 px-8 border-t border-white/5 hidden md:flex items-center justify-between text-xs text-zinc-500 uppercase tracking-widest font-bold">
        <div className="flex gap-8">
          <div className="flex items-center gap-2"><span className="w-1.5 h-1.5 bg-green-500 rounded-full"></span> Gemini 3 Pro Ready</div>
          <div>Поддержка: RU/TJK</div>
        </div>
        <div className="flex gap-4">
          <span>v2.1 Фабрика Бренда</span>
          <span className="text-amber-500/80">Premium Доступ</span>
        </div>
      </footer>
    </div>
  );
};

export default App;
